import React, { useEffect } from 'react';
import { Linking, Alert } from 'react-native';
import { NavigationContainer } from '@react-navigation/native';
import { createStackNavigator } from '@react-navigation/stack';

const Stack = createStackNavigator();

const App = () => {
  useEffect(() => {
    const handleDeepLink = async (event) => {
      if (event.url) {
        const url = event.url;
        const route = parseUrl(url);

        if (isValidRoute(route)) {
          navigateToScreen(route);
        } else {
          Alert.alert('Invalid link', 'Please try a different link.');
        }
      }
    };

    Linking.addEventListener('url', handleDeepLink);

    return () => {
      Linking.removeEventListener('url', handleDeepLink);
    };
  }, []);

  const parseUrl = (url) => {
    const parsedUrl = new URL(url);
    const pathParts = parsedUrl.pathname.split('/').filter(part => part !== '');

    if (pathParts[0] === 'profile' && pathParts.length === 2) {
      return { type: 'PROFILE', id: pathParts[1] };
    } else if (pathParts[0] === 'payment' && pathParts[1] === 'confirm') {
      return { type: 'PAYMENT_CONFIRM' };
    }

    return null;
  };

  const isValidRoute = (route) => {
    if (!route) return false;

    switch (route.type) {
      case 'PROFILE':
        return validateId(route.id);
      case 'PAYMENT_CONFIRM':
        return true; // Payment confirmation does not require validation
      default:
        return false;
    }
  };

  const validateId = (id) => {
    // Add your ID validation logic here
    return /^[0-9]+$/.test(id); // Example: Only allow numeric IDs
  };

  const navigateToScreen = (route) => {
    switch (route.type) {
      case 'PROFILE':
        navigation.navigate('Profile', { id: route.id });
        break;
      case 'PAYMENT_CONFIRM':
        navigation.navigate('PaymentConfirm');
        break;
      default:
        break;
    }
  };

  return (
    <NavigationContainer>
      <Stack.Navigator initialRouteName="Home">
        <Stack.Screen name="Home" component={HomeScreen} />
        <Stack.Screen name="Profile" component={ProfileScreen} />
        <Stack.Screen name="PaymentConfirm" component={PaymentConfirmScreen} />
      </Stack.Navigator>
    </NavigationContainer>
  );
};

export default App;